mapper.update:
UPDATE relation_event_inbox
SET status = #{status}, update_time = NOW()
WHERE fingerprint = #{fingerprint}

mapper.select:
SELECT id, event_type, fingerprint, payload, status, create_time, update_time
FROM relation_event_inbox
WHERE status = #{status}
ORDER BY update_time ASC
LIMIT #{limit}

mapper.delete:
DELETE FROM relation_event_inbox
WHERE status = #{status}
  AND update_time < #{before}
